const CHANNEL_CAPACITY: usize = 16_384;

// Input/output channels
let (in_tx, mut in_rx) = mpsc::channel::<api::RawEvent>(CHANNEL_CAPACITY);
let (out_tx, out_rx) = mpsc::channel::<api::EnrichedEvent>(CHANNEL_CAPACITY);
```

