     2→//! src/utils.rs
     3→//!
     4→//! General-purpose utilities shared across ChirpPulse services.
     5→//! Focus areas:
     6→//!   • Robust async retry with exponential back-off + jitter
     7→//!   • Task-spawn helpers with structured tracing
     8→//!   • Lightweight timing/metrics wrappers
     9→//!   • Misc. helpers (partition hashing, env access)
    10→//!
    11→//! These helpers allow individual micro-services to remain lean while still
    12→//! benefiting from consistent observability and failure-handling semantics.
    13→
    14→use rand::{thread_rng, Rng};
    15→use std::{
    16→    future::Future,
    17→    hash::Hasher,
    18→    pin::Pin,
    19→    time::{Duration, Instant},
    20→};
    21→use tokio::{task::JoinHandle, time::sleep};
    22→use tracing::{error, instrument, warn};
    23→
    24→/// Re-export a boxed error to simplify generic signatures within the
    25→/// application. We rely on `Send + Sync` so values can freely cross
    26→/// thread/async boundaries.
    27→pub type BoxError = Box<dyn std::error::Error + Send + Sync + 'static>;
    28→
    29→/// Unified error type for the `utils` module.
    30→///
    31→/// Use domain-specific errors in your service crates; convert to/from
    32→/// `UtilError` when necessary (e.g. for back-pressure signalling).
    33→#[derive(thiserror::Error, Debug)]
    34→pub enum UtilError {
    35→    /// All attempts have been consumed without success.
    36→    #[error("retries exhausted after {0} attempts")]
    37→    RetriesExhausted(usize),
    38→}
    39→
    40→/// Default maximum retry attempts when the caller supplies `0`.
    41→const DEFAULT_MAX_ATTEMPTS: usize = 5;
    42→
    43→/// Attempt an asynchronous operation multiple times with exponential back-off
    44→/// and ±20 % jitter.
    45→///
    46→/// • `operation` is an async closure producing `Result<T, E>`.  
    47→/// • `max_attempts == 0` triggers [`DEFAULT_MAX_ATTEMPTS`].  
    48→/// • `base_delay` is the initial sleep duration; it doubles each attempt.  
    49→///
    50→/// All errors are mapped to [`BoxError`] so we can treat them uniformly.
    51→///
    52→/// Example
    53→/// -------
    54→/// ```rust,no_run
    55→/// use chirp_pulse_utils::{retry_async, BoxError};
    56→/// use std::time::Duration;
    57→///
    58→/// async fn fetch() -> Result<(), BoxError> {
    59→///     // ... call a flaky upstream service ...
    60→/// #   Ok(())
    61→/// }
    62→///
    63→/// #[tokio::main]
    64→/// async fn main() -> Result<(), BoxError> {
    65→///     retry_async(
    66→///         || async { fetch().await },
    67→///         4,
    68→///         Duration::from_millis(100),
    69→///     )
    70→///     .await?;
    71→///     Ok(())
    72→/// }
    73→/// ```
    74→#[instrument(level = "trace", skip(operation))]
    75→pub async fn retry_async<F, Fut, T>(
    76→    mut operation: F,
    77→    max_attempts: usize,
    78→    base_delay: Duration,
    79→) -> Result<T, UtilError>
    80→where
    81→    F: FnMut() -> Fut + Send + 'static,
    82→    Fut: Future<Output = Result<T, BoxError>> + Send,
    83→    T: Send + 'static,
    84→{
    85→    let max_attempts = if max_attempts == 0 {
    86→        DEFAULT_MAX_ATTEMPTS
    87→    } else {
    88→        max_attempts
    89→    };
    90→
    91→    let mut attempt = 0usize;
    92→    loop {
    93→        attempt += 1;
    94→
    95→        match operation().await {
    96→            Ok(val) => return Ok(val),
    97→            Err(err) => {
    98→                if attempt >= max_attempts {
    99→                    error!(attempt, error = %err, "operation failed; retry limit reached");
   100→                    return Err(UtilError::RetriesExhausted(attempt));
   101→                }
   102→
   103→                // Calc delay = base * 2^(attempt-1) ±20 % jitter
   104→                let exp_delay = base_delay * 2_u32.pow((attempt - 1) as u32);
   105→                let jitter_factor = thread_rng().gen_range(0.8..=1.2);
   106→                let sleep_for = exp_delay.mul_f32(jitter_factor as f32);
   107→
   108→                warn!(
   109→                    attempt,
   110→                    max_attempts,
   111→                    error = %err,
   112→                    retry_in_ms = sleep_for.as_millis(),
   113→                    "operation failed; retrying…"
   114→                );
   115→
   116→                sleep(sleep_for).await;
   117→            }
   118→        }
   119→    }
   120→}
   121→
   122→/// Spawn a Tokio task with a meaningful name and automatic error logging.
   123→///
   124→/// Panics inside the task are propagated to the parent runtime (Tokio
   125→/// already aborts by default). _Error_ values returned from the task are
   126→/// logged but do **not** bubble up, preventing accidental unawaited
   127→/// `JoinHandle` leaks.
   128→///
   129→/// Returns the [`JoinHandle`] so callers may `.await`/`.abort()` as needed.
   130→///
   131→/// ```rust,no_run
   132→/// use chirp_pulse_utils::{spawn_named_task, BoxError};
   133→///
   134→/// async fn job() -> Result<(), BoxError> {
   135→///     // ... do work ...
   136→/// #   Ok(())
   137→/// }
   138→///
   139→/// let handle = spawn_named_task("my_background_job", job());
   140→/// ```
   141→pub fn spawn_named_task<F>(name: &'static str, fut: F) -> JoinHandle<()>
   142→where
   143→    F: Future<Output = Result<(), BoxError>> + Send + 'static,
   144→{
   145→    tokio::task::Builder::new()
   146→        .name(name)
   147→        .spawn(async move {
   148→            if let Err(err) = fut.await {
   149→                error!(task = name, error = %err, "task exited with error");
   150→            }
   151→        })
   152→        .expect("failed to spawn task")
   153→}
   154→
   155→/// Time an async operation and submit the duration as a histogram metric.
   156→///
   157→/// Even if `metrics` is disabled at compile-time, the no-op macro
   158→/// ensures zero runtime cost.
   159→///
   160→/// ```rust,no_run
   161→/// use chirp_pulse_utils::measure_time_async;
   162→///
   163→/// # async fn compute() {}
   164→/// let _ = measure_time_async("my_op.latency_seconds", || async { compute().await }).await;
   165→/// ```
   166→#[instrument(level = "trace", skip(operation))]
   167→pub async fn measure_time_async<F, Fut, T>(metric_name: &'static str, operation: F) -> T
   168→where
   169→    F: FnOnce() -> Fut,
   170→    Fut: Future<Output = T>,
   171→{
   172→    let start = Instant::now();
   173→    let res = operation().await;
   174→    let elapsed = start.elapsed();
   175→    metrics::histogram!(metric_name, elapsed.as_secs_f64());
   176→    res
   177→}
   178→
   179→/// Retrieve the value of an environment variable or panic with a descriptive
   180→/// message. Suitable for required configuration keys that should fail fast
   181→/// during service boot.
   182→pub fn env_var(key: &str) -> String {
   183→    match std::env::var(key) {
   184→        Ok(v) => v,
   185→        Err(_) => {
   186→            let msg = format!("environment variable `{key}` must be set");
   187→            error!("{msg}");
   188→            panic!("{msg}");
   189→        }
   190→    }
   191→}
   192→
   193→/// Compute a stable 64-bit partition key for the given input string.
   194→///
   195→/// We use FNV-1a (fast, non-cryptographic) so identical inputs always hash to
   196→/// the same value, enabling event-ordering guarantees when producing to
   197→/// Kafka/Kinesis.
   198→///
   199→/// Example:
   200→/// ```
   201→/// use chirp_pulse_utils::partition_key_from_str;
   202→/// let key = partition_key_from_str("@elonmusk");
   203→/// ```
   204→pub fn partition_key_from_str(input: &str) -> u64 {
   205→    let mut hasher = fnv::FnvHasher::default();
   206→    hasher.write(input.as_bytes());
   207→    hasher.finish()
   208→}
   209→
   210→/////////////////////////////
   211→//           Tests         //
   212→/////////////////////////////
   213→
   214→#[cfg(test)]
   215→mod tests {
   216→    use super::*;
   217→    use tokio::runtime::Runtime;
   218→
   219→    #[test]
   220→    fn hash_is_stable() {
   221→        let a = partition_key_from_str("hello");
   222→        let b = partition_key_from_str("hello");
   223→        assert_eq!(a, b);
   224→    }
   225→
   226→    #[test]
   227→    fn retry_succeeds_eventually() {
   228→        let rt = Runtime::new().unwrap();
   229→        let mut failures_left = 2usize;
   230→
   231→        let result = rt
   232→            .block_on(async {
   233→                retry_async(
   234→                    || {
   235→                        Box::pin(async {
   236→                            if failures_left > 0 {
   237→                                failures_left -= 1;
   238→                                Err("transient failure".into())
   239→                            } else {
   240→                                Ok(123u32)
   241→                            }
   242→                        }) as Pin<Box<dyn Future<Output = Result<u32, BoxError>> + Send>>
   243→                    },
   244→                    5,
   245→                    Duration::from_millis(10),
   246→                )
   247→                .await
   248→            })
   249→            .unwrap();
   250→
   251→        assert_eq!(result, 123);
   252→        assert_eq!(failures_left, 0);
   253→    }
   254→}
