84: #[derive(Debug, Error)]
85: pub enum ProcessorError {
86:     #[error("kafka error: {0}")]
87:     Kafka(#[from] KafkaError),
88:     #[error("strategy '{0}' not found")]
89:     StrategyNotFound(String),
90:     #[error("json serialization error: {0}")]
91:     Json(#[from] serde_json::Error),
92:     #[error("channel error: {0}")]
93:     Channel(#[from] mpsc::error::SendError<OwnedMessage>),
94:     #[error("other: {0}")]
95:     Other(String),
96: }
97: 
98: ///////////////////////////////////////////////////////////////////////////////
99: // Sentiment Strategy Pattern
100: ///////////////////////////////////////////////////////////////////////////////
101: 
102: /// Trait representing any sentiment analysis algorithm.
103: ///
104: /// The `analyze` function is async to allow network calls (e.g., model server).
105: #[async_trait]
106: pub trait SentimentStrategy: Send + Sync + 'static {
107:     /// Identifier shown in telemetry and persisted to records.
108:     fn name(&self) -> &'static str;
109: 
110:     /// Perform sentiment analysis on the given message body.
111:     async fn analyze(&self, text: &str) -> Result<SentimentScore, ProcessorError>;
112: }
113: 
114: /// Trivial implementation that returns neutral sentiment.
115: /// Useful as a circuit-breaker fallback.
116: pub struct NeutralStrategy;
117: 
118: #[async_trait]
119: impl SentimentStrategy for NeutralStrategy {
120:     fn name(&self) -> &'static str {
121:         "neutral"
122:     }
123: 
124:     async fn analyze(&self, _text: &str) -> Result<SentimentScore, ProcessorError> {
125:         Ok(SentimentScore {
126:             polarity: 0.0,
127:             confidence: 0.0,
128:             meta: None,
129:         })
130:     }
131: }
132: 
133: /// Example lexical strategy that looks for positive/negative keywords
134: /// (purely demonstrative – not production grade).
135: pub struct LexiconStrategy {
136:     positives: Vec<&'static str>,
137:     negatives: Vec<&'static str>,
138: }
139: 
140: impl Default for LexiconStrategy {
141:     fn default() -> Self {
142:         Self {
143:             positives: vec!["good", "great", "love", "excellent", "happy"],
144:             negatives: vec!["bad", "hate", "terrible", "awful", "sad"],
145:         }
146:     }
147: }
148: 
149: #[async_trait]
150: impl SentimentStrategy for LexiconStrategy {
151:     fn name(&self) -> &'static str {
152:         "lexicon_v1"
153:     }
154: 
155:     async fn analyze(&self, text: &str) -> Result<SentimentScore, ProcessorError> {
156:         let mut score = 0f32;
157:         let mut hits = 0u32;
158: 
159:         for token in text.split_whitespace() {
160:             if self.positives.iter().any(|p| token.eq_ignore_ascii_case(p)) {
161:                 score += 1.0;
162:                 hits += 1;
163:             } else if self.negatives.iter().any(|n| token.eq_ignore_ascii_case(n)) {
164:                 score -= 1.0;
165:                 hits += 1;
166:             }
167:         }
168: 
169:         if hits == 0 {
170:             // Unknown sentiment
171:             return Ok(SentimentScore {
172:                 polarity: 0.0,
173:                 confidence: 0.0,
174:                 meta: None,
175:             });
176:         }
177: 
178:         let polarity = (score / hits as f32).clamp(-1.0, 1.0);
179:         Ok(SentimentScore {
180:             polarity,
181:             confidence: (hits as f32 / text.split_whitespace().count() as f32).clamp(0.0, 1.0),
182:             meta: None,
183:         })
184:     }
185: }
186: 
187: /// Registry containing all available strategies and the currently active default one.
188: #[derive(Clone)]
189: pub struct StrategyRegistry {
190:     strategies: Arc<RwLock<HashMap<String, Arc<dyn SentimentStrategy>>>>,
191:     default: Arc<RwLock<String>>,
192: }
193: 
194: impl StrategyRegistry {
195:     pub fn new() -> Self {
196:         let mut map: HashMap<String, Arc<dyn SentimentStrategy>> = HashMap::new();
197:         let neutral = Arc::new(NeutralStrategy);
198:         map.insert(neutral.name().to_owned(), neutral.clone());
199: 
200:         let lex = Arc::new(LexiconStrategy::default());
201:         map.insert(lex.name().to_owned(), lex.clone());
202: 
203:         Self {
204:             strategies: Arc::new(RwLock::new(map)),
205:             default: Arc::new(RwLock::new(lex.name().to_owned())),
206:         }
207:     }
208: 
209:     /// Register or override a strategy at runtime.
210:     pub async fn register<S: SentimentStrategy>(&self, strategy: S) {
211:         let name = strategy.name().to_owned();
212:         self.strategies
213:             .write()
214:             .await
215:             .insert(name, Arc::new(strategy));
216:     }
217: 
218:     /// Promote the named strategy to be the default going forward.
219:     pub async fn promote_default(&self, name: &str) -> Result<(), ProcessorError> {
220:         let read = self.strategies.read().await;
221:         if read.contains_key(name) {
222:             *self.default.write().await = name.to_owned();
223:             Ok(())
224:         } else {
225:             Err(ProcessorError::StrategyNotFound(name.to_owned()))
226:         }
227:     }
228: 
229:     /// Get the current default strategy.
230:     pub async fn default(&self) -> Arc<dyn SentimentStrategy> {
231:         let name = self.default.read().await.clone();
232:         self.get(&name)
233:             .await
234:             .unwrap_or_else(|_| Arc::new(NeutralStrategy))
235:     }
236: 
237:     /// Fetch a strategy by name.
238:     pub async fn get(&self, name: &str) -> Result<Arc<dyn SentimentStrategy>, ProcessorError> {
239:         self.strategies
240:             .read()
241:             .await
242:             .get(name)
243:             .cloned()
244:             .ok_or_else(|| ProcessorError::StrategyNotFound(name.into()))
245:     }
246: }
