175: /// Duplicate-detection using a Bloom filter plus exact check fallback.
176: ///
177: /// The filter gives an O(1) approximate membership test with controllable
178: /// false-positive rate.  We complement it with an exact check in the
179: /// concurrent `DashSet` to eliminate false positives at the cost of
180: /// additional in-RAM storage for the most recent `DEDUP_CAPACITY` IDs.
181: pub struct DuplicateDetector {
182:     // Fast, memory-efficient approximate set.
183:     bloom: RwLock<BloomFilter>,
184:     // Slow but exact set of recent IDs.  Evicted by size limits.
185:     exact: DashSet<String>,
186: }
187: 
188: impl DuplicateDetector {
189:     pub fn new(capacity: usize, fp_rate: f64) -> Self {
190:         Self {
191:             bloom: RwLock::new(BloomFilter::with_rate(fp_rate, capacity)),
192:             exact: DashSet::with_capacity(capacity),
193:         }
194:     }
195: }
196: 
197: #[async_trait]
198: impl QualityRule for DuplicateDetector {
199:     fn name(&self) -> &'static str {
200:         "duplicate_detector"
201:     }
202: 
203:     async fn check(&self, event: &mut SocialEvent) -> Result<(), QualityError> {
204:         let id = &event.event_id;
205: 
206:         // First, try the Bloom filter (approximate).
207:         {
208:             let bloom = self.bloom.read().await;
209:             if !bloom.contains(id) {
210:                 // Definitely not seen before.  Mark in Bloom filter and exact set.
211:                 drop(bloom);
212:                 {
213:                     let mut bloom = self.bloom.write().await;
214:                     bloom.insert(id);
215:                 }
216:                 self.exact.insert(id.clone());
217:                 return Ok(());
218:             }
219:         }
220:         // Bloom filter says "maybe". Perform exact check.
221:         if self.exact.contains(id) {
222:             Err(QualityError::Duplicate)
223:         } else {
224:             // False positive, record now.
225:             {
226:                 let mut bloom = self.bloom.write().await;
227:                 bloom.insert(id);
228:             }
229:             // Evict if over capacity.
230:             if self.exact.len() >= DEDUP_CAPACITY {
231:                 if let Some(first) = self.exact.iter().next() {
232:                     self.exact.remove(first.key());
233:                 }
234:             }
235:             self.exact.insert(id.clone());
236:             Ok(())
237:         }
238:     }
239: }
