245: /// Convert a borrowed Kafka message to `SocialEvent`.
246: fn deserialize_event(msg: &BorrowedMessage<'_>) -> Result<SocialEvent, serde_json::Error> {
247:     serde_json::from_slice::<SocialEvent>(msg.payload().unwrap_or_default())
248: }
249: 
250: /// Wrapper around a `StreamConsumer` that yields deserialized `SocialEvent`s.
251: fn kafka_event_stream<'a>(
252:     consumer: &'a StreamConsumer,
253: ) -> impl Stream<Item = Result<SocialEvent, PipelineError>> + 'a {
254:     consumer
255:         .stream()
256:         .map(|result| match result {
257:             Err(e) => Err(PipelineError::Source(e.to_string())),
258:             Ok(m) => deserialize_event(&m).map_err(PipelineError::from),
259:         })
260: }
