266: /// Async sink that pushes JSON serialised events to a Kafka topic.
267: struct KafkaJsonSink {
268:     producer: FutureProducer,
269:     topic: &'static str,
270: }
271: 
272: impl KafkaJsonSink {
273:     fn new(brokers: &str, topic: &'static str) -> anyhow::Result<Self> {
274:         let producer = ClientConfig::new()
275:             .set("bootstrap.servers", brokers)
276:             .set("message.timeout.ms", PRODUCER_TIMEOUT_MS.to_string())
277:             .create()?;
278:         Ok(Self { producer, topic })
279:     }
280: 
281:     #[instrument(skip_all, fields(topic = self.topic))]
282:     async fn send(&self, event: &SocialEvent) -> Result<(), SinkError> {
283:         let payload = serde_json::to_vec(event)?;
284:         let record = FutureRecord::to(self.topic)
285:             .key(&event.event_id)
286:             .payload(&payload);
287:         let produce_future = self.producer.send(record, Duration::from_millis(PRODUCER_TIMEOUT_MS));
288: 
289:         match produce_future.await {
290:             Ok(Ok(_)) => Ok(()),
291:             Ok(Err((e, _))) | Err((e, _)) => Err(SinkError::Produce(e.to_string())),
292:         }
293:     }
294: }
