257: fn kafka_config(brokers: &str, group_id: &str) -> ClientConfig {
258:     let mut cfg = ClientConfig::new();
259:     cfg.set("bootstrap.servers", brokers)
260:         .set("enable.auto.commit", "false")
261:         .set("auto.offset.reset", "earliest")
262:         .set("group.id", group_id)
263:         .set("fetch.message.max.bytes", "1048576") // 1 MiB
264:         .set("message.timeout.ms", "5000");
265:     cfg
266: }
