268: fn build_consumer(brokers: &str, group_id: &str) -> Result<StreamConsumer, KafkaError> {
269:     kafka_config(brokers, group_id)
270:         .create::<StreamConsumer>()
271: }
272: 
273: fn build_producer(brokers: &str) -> Result<FutureProducer, KafkaError> {
274:     ClientConfig::new()
275:         .set("bootstrap.servers", brokers)
276:         .set("message.timeout.ms", "5000")
277:         .set("compression.type", "lz4")
278:         .create::<FutureProducer>()
279: }
