281: ///////////////////////////////////////////////////////////////////////////////
282: // Stream Processor
283: ///////////////////////////////////////////////////////////////////////////////
284: 
285: pub struct StreamProcessor {
286:     registry: StrategyRegistry,
287:     consumer: StreamConsumer,
288:     producer: FutureProducer,
289: }
290: 
291: impl StreamProcessor {
292:     pub fn new(
293:         registry: StrategyRegistry,
294:         consumer: StreamConsumer,
295:         producer: FutureProducer,
296:     ) -> Self {
297:         Self {
298:             registry,
299:             consumer,
300:             producer,
301:         }
302:     }
303: 
304:     /// Run the event loop until process is terminated.
305:     pub async fn run(mut self) -> Result<(), ProcessorError> {
306:         // Subscribe to both the data topic and the control topic
307:         self.consumer
308:             .subscribe(&[INPUT_TOPIC, STRATEGY_CONTROL_TOPIC])?;
309: 
310:         info!("Sentiment enrichment processor started, awaiting messages...");
311:         let (dlq_tx, mut dlq_rx) = mpsc::channel::<OwnedMessage>(1024);
312: 
313:         // Spawn DLQ producer
314:         let producer_clone = self.producer.clone();
315:         tokio::spawn(async move {
316:             while let Some(msg) = dlq_rx.recv().await {
317:                 let payload = msg.payload().unwrap_or_default();
318:                 if let Err(e) = producer_clone
319:                     .send(
320:                         FutureRecord::to(DLQ_TOPIC)
321:                             .payload(payload)
322:                             .key(msg.key().unwrap_or_default()),
323:                         Duration::from_secs(0),
324:                     )
325:                     .await
326:                 {
327:                     error!("failed to produce to DLQ: {}", e.0);
328:                 }
329:             }
330:         });
331: 
332:         let stream = self.consumer.stream();
333:         tokio::pin!(stream);
334: 
335:         while let Some(result) = stream.next().await {
336:             match result {
337:                 Ok(msg) => {
338:                     let topic = msg.topic().to_owned();
339:                     let owned = msg.detach();
340: 
341:                     let registry = self.registry.clone();
342:                     let producer = self.producer.clone();
343:                     let dlq_tx = dlq_tx.clone();
344: 
345:                     tokio::spawn(async move {
346:                         if let Err(err) =
347:                             Self::handle_message(owned, &topic, registry, producer, dlq_tx).await
348:                         {
349:                             error!("processing error: {:?}", err);
350:                         }
351:                     });
352:                 }
353:                 Err(e) => {
354:                     warn!("Kafka error encountered: {}", e);
355:                 }
356:             }
357:         }
358:         Ok(())
359:     }
360: 
361:     async fn handle_message(
362:         msg: OwnedMessage,
363:         topic: &str,
364:         registry: StrategyRegistry,
365:         producer: FutureProducer,
366:         dlq_tx: mpsc::Sender<OwnedMessage>,
367:     ) -> Result<(), ProcessorError> {
368:         match topic {
369:             INPUT_TOPIC => {
370:                 let payload = std::str::from_utf8(msg.payload().unwrap_or_default())
371:                     .map_err(|e| ProcessorError::Other(e.to_string()))?;
372: 
373:                 let social: SocialMessage = match serde_json::from_str(payload) {
374:                     Ok(v) => v,
375:                     Err(e) => {
376:                         warn!("invalid JSON payload, sending to DLQ: {}", e);
377:                         dlq_tx.send(msg).await?;
378:                         return Ok(());
379:                     }
380:                 };
381: 
382:                 let strategy = registry.default().await;
383:                 let sentiment = strategy.analyze(&social.text).await?;
384: 
385:                 let enriched = EnrichedSocialMessage {
386:                     original: social,
387:                     sentiment,
388:                     strategy: strategy.name().to_owned(),
389:                     enriched_at: SystemTime::now(),
390:                 };
391: 
392:                 let serialized = serde_json::to_vec(&enriched)?;
393: 
394:                 // produce to output topic
395:                 producer
396:                     .send(
397:                         FutureRecord::to(OUTPUT_TOPIC)
398:                             .payload(&serialized)
399:                             .key(&enriched.original.id),
400:                         Duration::from_secs(0),
401:                     )
402:                     .await
403:                     .map_err(|(e, _)| ProcessorError::Kafka(e))?;
404: 
405:                 // manual commit
406:                 if let Err(e) = msg.commit(&producer.client(), rdkafka::consumer::CommitMode::Async)
407:                 {
408:                     warn!("commit failed: {}", e);
409:                 }
410:             }
411:             STRATEGY_CONTROL_TOPIC => {
412:                 let cmd: StrategyControl =
413:                     serde_json::from_slice(msg.payload().unwrap_or_default())?;
414: 
415:                 match cmd {
416:                     StrategyControl::Promote { name } => {
417:                         registry.promote_default(&name).await?;
418:                         info!("Promoted strategy '{}' as new default", &name);
419:                     }
420:                 }
421:             }
422:             _ => {
423:                 warn!("message on unexpected topic '{}', ignoring", topic);
424:             }
425:         }
426:         Ok(())
427:     }
428: }
