{"content":"300: /// Thread-safe, hot-swapable registry of `QualityRule`s.
301: ///
302: /// Data scientists can update the active ruleset at run-time by calling
303: /// [`RuleRegistry::replace_rules`] with a freshly built vector.
304: #[derive(Default)]
305: pub struct RuleRegistry {
306:     inner: RwLock<Vec<Arc<dyn QualityRule>>>,
307: }
308: 
309: impl RuleRegistry {
310:     pub fn new(initial: Vec<Arc<dyn QualityRule>>) -> Self {
311:         Self {
312:             inner: RwLock::new(initial),
313:         }
314:     }
315: 
316:     /// Atomically replace the full ruleset.
317:     pub async fn replace_rules(&self, rules: Vec<Arc<dyn QualityRule>>) {
318:         let mut guard = self.inner.write().await;
319:         *guard = rules;
320:         info!(count = guard.len(), "Replaced quality-ruleset");
321:     }
322: 
323:     /// Fetch a snapshot clone of the current rules.
324:     pub async fn snapshot(&self) -> Vec<Arc<dyn QualityRule>> {
325:         self.inner.read().await.clone()
326:     }
327: }
328: 
329: /// The main orchestrator that wires sources, rules and sink.
330: pub struct QualityPipeline {
331:     rules: Arc<RuleRegistry>,
332:     sink: Arc<KafkaJsonSink>,
333:     cancel: Arc<RwLock<bool>>,
334: }
335: 
336: impl QualityPipeline {
337:     pub fn new(rules: Arc<RuleRegistry>, sink: Arc<KafkaJsonSink>) -> Self {
338:         Self {
339:             rules,
340:             sink,
341:             cancel: Arc::new(RwLock::new(false)),
342:         }
343:     }
344: 
345:     /// Request graceful shutdown.
346:     pub async fn shutdown(&self) {
347:         let mut guard = self.cancel.write().await;
348:         *guard = true;
349:     }
350: 
351:     /// Consumes from `consumer` indefinitely until `shutdown` is called.
352:     #[instrument(skip_all, name = "quality_pipeline")]
353:     pub async fn run(&self, consumer: StreamConsumer) -> anyhow::Result<()> {
354:         info!("QC Pipeline starting");
355:         // Subscribe to topic.
356:         consumer.subscribe(&[SOURCE_TOPIC])?;
357: 
358:         // Stream loop with back-pressure.
359:         let mut stream = kafka_event_stream(&consumer);
360: 
361:         loop {
362:             select! {
363:                 cancelled = self.cancel.read(), if *cancelled => {
364:                     info!("QC Pipeline received shutdown signal");
365:                     break;
366:                 }
367:                 maybe_msg = stream.next() => {
368:                     match maybe_msg {
369:                         None => {
370:                             warn!("Event stream unexpectedly ended");
371:                             break;
372:                         }
373:                         Some(Err(err)) => {
374:                             error!(error = %err, "Event stream error");
375:                             counter!("pipeline_errors_total", 1, "stage" => "source");
376:                         }
377:                         Some(Ok(mut event)) => {
378:                             // Process one event
379:                             let start = SystemTime::now();
380: 
381:                             match self.process_event(&mut event).await {
382:                                 Ok(()) => {
383:                                     let latency = SystemTime::now()
384:                                         .duration_since(start)
385:                                         .unwrap_or_default()
386:                                         .as_millis() as f64;
387:                                     histogram!("pipeline_event_latency_ms", latency);
388:                                 }
389:                                 Err(e) => {
390:                                     error!(error = %e, "Processing error");
391:                                     counter!("pipeline_errors_total", 1, "stage" => "processing");
392:                                     // Push to DLQ
393:                                     if let Err(dlq_err) = self.sink_dead_letter(&event, &e).await {
394:                                         error!(error = %dlq_err, "Failed to write to DLQ");
395:                                         counter!("pipeline_errors_total", 1, "stage" => "dlq");
396:                                     }
397:                                 }
398:                             }
399:                         }
400:                     }
401:                 }
402:             }
403:         }
404: 
405:         info!("QC Pipeline stopped");
406:         Ok(())
407:     }
408: 
409:     #[instrument(skip_all)]
410:     async fn process_event(&self, event: &mut SocialEvent) -> Result<(), PipelineError> {
411:         let rules = self.rules.snapshot().await;
412: 
413:         for rule in rules.iter() {
414:             // For every rule we catch its error separately to emit per-rule metrics.
415:             match rule.check(event).await {
416:                 Ok(()) => increment_counter!("rule_pass_total", "rule" => rule.name()),
417:                 Err(err) => {
418:                     increment_counter!("rule_fail_total", "rule" => rule.name());
419:                     return Err(PipelineError::Rule(err));
420:                 }
421:             }
422:         }
423: 
424:         // Forward to sink
425:         self.sink.send(event).await?;
426:         Ok(())
427:     }
428: 
429:     #[instrument(skip_all)]
430:     async fn sink_dead_letter(
431:         &self,
432:         event: &SocialEvent,
433:         err: &PipelineError,
434:     ) -> Result<(), SinkError> {
435:         let payload = DeadLetterPayload::new(event, err);
436:         let dlq_sink = &*self.sink; // reuse underlying producer, different topic
437:         let record = FutureRecord::to(DLQ_TOPIC)
438:             .key(&event.event_id)
439:             .payload(&serde_json::to_vec(&payload)?);
440: 
441:         match dlq_sink
442:             .producer
443:             .send(record, Duration::from_millis(PRODUCER_TIMEOUT_MS))
444:             .await
445:         {
446:             Ok(Ok(_)) => Ok(()),
447:             Ok(Err((e, _))) | Err((e, _)) => Err(SinkError::Produce(e.to_string())),
448:         }
449:     }
450: }
