454: //
455: 
456: #[derive(Debug, Serialize)]
457: struct DeadLetterPayload<'a> {
458:     event: &'a SocialEvent,
459:     error: String,
460:     failed_at: u64,
461: }
462: 
463: impl<'a> DeadLetterPayload<'a> {
464:     fn new(event: &'a SocialEvent, error: &PipelineError) -> Self {
465:         let failed_at = SystemTime::now()
466:             .duration_since(UNIX_EPOCH)
467:             .unwrap_or_default()
468:             .as_millis() as u64;
469:         Self {
470:             event,
471:             error: error.to_string(),
472:             failed_at,
473:         }
474:     }
475: }
