190: // --------------- Sentiment Engine --------------------------------
191: 
192: pub struct SentimentEngine {
193:     /// Sender for raw events
194:     pub in_tx: mpsc::Sender<api::RawEvent>,
195:     /// Receiver for enriched events
196:     pub out_rx: mpsc::Receiver<api::EnrichedEvent>,
197:     /// Handle to shutdown signal
198:     shutdown_tx: watch::Sender<bool>,
199: }
200: 
201: impl SentimentEngine {
202:     /// Spin up the engine using an initial config file.
203:     ///
204:     /// The function returns immediately; internal tasks live on the Tokio
205:     /// runtime until the [`SentimentEngine`] instance is dropped.
206:     pub async fn new<P: Into<PathBuf>>(config_path: P) -> Result<Self> {
207:         let config_path = config_path.into();
208:         let cfg = load_config(&config_path).await?;
209: 
210:         // Watch channel for strategy updates
211:         let (strategy_tx, strategy_rx) =
212:             watch::channel::<Arc<dyn SentimentStrategy>>(cfg.strategy.build());
213: 
214:         // Watch channel for shutdown
215:         let (shutdown_tx, shutdown_rx) = watch::channel(false);
216: 
217:         // Input/output channels
218:         let (in_tx, mut in_rx) = mpsc::channel::<api::RawEvent>(CHANNEL_CAPACITY);
219:         let (out_tx, out_rx) = mpsc::channel::<api::EnrichedEvent>(CHANNEL_CAPACITY);
220: 
221:         // Spawn config-file watcher
222:         let watcher_strategy_tx = strategy_tx.clone();
223:         let watcher_shutdown = shutdown_rx.clone();
224:         tokio::spawn(async move {
225:             if let Err(e) = watch_config_file(
226:                 config_path,
227:                 watcher_strategy_tx,
228:                 watcher_shutdown,
229:             )
230:             .await
231:             {
232:                 error!(%e, "config-file watcher failed");
233:             }
234:         });
235: 
236:         // Spawn worker pool
237:         for id in 0..cfg.parallelism {
238:             let mut local_in_rx = in_rx.clone();
239:             let out_tx = out_tx.clone();
240:             let mut strategy_rx = strategy_rx.clone();
241:             let mut shutdown_rx = shutdown_rx.clone();
242:             task::Builder::new()
243:                 .name(&format!("sentiment-worker-{id}"))
244:                 .spawn(async move {
245:                     while let Some(event) = select! {
246:                         biased;
247:                         _ = shutdown_rx.changed() => break,
248:                         maybe = local_in_rx.recv() => maybe,
249:                     } {
250:                         process_event(event, &out_tx, &mut strategy_rx).await;
251:                     }
252:                     debug!("worker {id} exiting");
253:                 })
254:                 .expect("spawn sentiment worker");
255:         }
256: 
257:         Ok(Self {
258:             in_tx,
259:             out_rx,
260:             shutdown_tx,
261:         })
262:     }
263: }
264: 
265: impl Drop for SentimentEngine {
266:     fn drop(&mut self) {
267:         let _ = self.shutdown_tx.send(true);
268:     }
269: }
