273: async fn process_event(
274:     event: api::RawEvent,
275:     out_tx: &mpsc::Sender<api::EnrichedEvent>,
276:     strategy_rx: &mut watch::Receiver<Arc<dyn SentimentStrategy>>,
277: ) {
278:     let start = Instant::now();
279:     // Obtain current strategy
280:     let strategy = strategy_rx.borrow().clone();
281: 
282:     match strategy.score(&event.text).await {
283:         Ok(score) => {
284:             let enriched = api::EnrichedEvent {
285:                 id: event.id,
286:                 user_id: event.user_id,
287:                 text: event.text,
288:                 timestamp: event.timestamp,
289:                 sentiment: score,
290:                 processed_at: chrono::Utc::now().timestamp_millis(),
291:                 strategy_version: strategy.version().to_string(),
292:             };
293:             if let Err(e) = out_tx.send(enriched).await {
294:                 warn!(%e, "failed to forward enriched event");
295:             }
296:         }
297:         Err(e) => {
298:             error!(%e, "sentiment scoring failed");
299:         }
300:     }
301:     debug!(
302:         elapsed_ms = start.elapsed().as_millis(),
303:         strategy = strategy.version(),
304:         "event processed"
305:     );
306: }
