308: /// Watch the config file for changes and update the active strategy when the
309: /// `strategy` field changes.
310: async fn watch_config_file(
311:     path: PathBuf,
312:     strategy_tx: watch::Sender<Arc<dyn SentimentStrategy>>,
313:     mut shutdown_rx: watch::Receiver<bool>,
314: ) -> Result<()> {
315:     // Initial canonicalised metadata so we can detect self-events
316:     let mut last_modified = fs::metadata(&path).await?.modified()?;
317: 
318:     let (evt_tx, mut evt_rx) = tokio::sync::mpsc::channel(8);
319: 
320:     // Spawn the synchronous notify watcher on a blocking thread
321:     let mut watcher: RecommendedWatcher = Watcher::new(
322:         move |res| {
323:             if let Ok(event) = res {
324:                 let _ = evt_tx.blocking_send(event);
325:             }
326:         },
327:         NotifyConfig::default().with_poll_interval(Duration::from_secs(3)),
328:     )?;
329:     watcher.watch(&path, RecursiveMode::NonRecursive)?;
