209: /// Runtime handle for the enrichment & validation pipeline.
210: pub struct Pipeline {
211:     enrichers: Vec<Arc<dyn Enricher>>,
212:     quality_gate: Arc<dyn QualityGate>,
213: 
214:     // Metrics
215:     m_events_total: Counter<u64>,
216:     m_failures: Counter<u64>,
217:     h_latency: Histogram<f64>,
218: }
219: 
220: impl Pipeline {
221:     pub fn new(
222:         enrichers: Vec<Arc<dyn Enricher>>,
223:         quality_gate: Arc<dyn QualityGate>,
224:     ) -> Self {
225:         let meter: Meter = global::meter("chirp_pulse.pipeline");
226: 
227:         Self {
228:             enrichers,
229:             quality_gate,
230:             m_events_total: meter.u64_counter("events_total").init(),
231:             m_failures: meter.u64_counter("events_failed").init(),
232:             h_latency: meter.f64_histogram("latency_ms").init(),
233:         }
234:     }
235: 
236:     /// Main loop: consumes social events, performs enrichment +
237:     /// validation, and pushes valid events to the downstream channel.
238:     ///
239:     /// Errors never bubble up; instead we leverage back-pressure by
240:     /// sleeping and re-queueing internally, preventing lost messages.
241:     #[instrument(skip_all, fields(enrichers = %self.enrichers.len()))]
242:     pub async fn run(
243:         self: Arc<Self>,
244:         mut rx: Receiver<SocialEvent>,
245:         tx: Sender<EnrichedEvent>,
246:         quarantine_tx: Sender<EnrichedEvent>,
247:     ) {
248:         let mut backoff = Duration::from_millis(100);
249: 
250:         while let Some(event) = rx.recv().await {
251:             self.m_events_total.add(1, &[]);
252: 
253:             let start_time = Instant::now();
254:             match self
255:                 .process_event(event.clone())
256:                 .await
257:                 .with_context(|| format!("processing event {}", event.id))
258:             {
259:                 Ok(Some(enriched)) => {
260:                     if let Err(e) = tx.send(enriched).await {
261:                         // Downstream channel is closed; escalate.
262:                         error!(error = ?e, "output channel dropped, shutting down pipeline");
263:                         break;
264:                     }
265: 
266:                     self.h_latency
267:                         .record(start_time.elapsed().as_secs_f64() * 1_000.0, &[]);
268:                 }
269:                 Ok(None) => {
270:                     debug!(id = %event.id, "quarantined after validation failure");
271:                 }
272:                 Err(e) => {
273:                     self.m_failures.add(1, &[]);
274:                     error!(error = ?e, "fatal enrichment failure; scheduling retry");
275:                     // Simple exponential back-off
276:                     time::sleep(backoff).await;
277:                     backoff = (backoff * 2).min(Duration::from_secs(30));
278:                     // Re-queue the original event.
279:                     if let Err(e) = rx.send(event).await {
280:                         error!(error = ?e, "failed to re-queue event; discarding");
281:                     }
282:                 }
283:             }
284:         }
285: 
286:         info!("pipeline terminated – no more input");
287:     }
