290:     async fn process_event(&self, event: SocialEvent) -> Result<Option<EnrichedEvent>> {
291:         let mut enriched: EnrichedEvent = event.into();
292: 
293:         for enricher in &self.enrichers {
294:             debug!(stage = enricher.name(), "running enricher");
295:             enricher
296:                 .enrich(&mut enriched)
297:                 .await
298:                 .with_context(|| format!("enricher {}", enricher.name()))?;
299:         }
300: 
301:         // Post-stage validation
302:         let ok = self.quality_gate.validate(&enriched).await?;
303:         if ok {
304:             Ok(Some(enriched))
305:         } else {
306:             Ok(None)
307:         }
308:     }
309: }
