311: /// Spawns the streaming pipeline.
312: ///
313: /// Consumes events from the given [`Stream`], processes them concurrently, and
314: /// publishes them to the supplied [`Sender`].
315: ///
316: /// The caller is responsible for providing a bounded channel with sufficient
317: /// capacity to handle downstream back-pressure.
318: ///
319: /// Returns once the input stream ends or a fatal error occurs.
320: pub async fn run_pipeline<S>(
321:     pipeline: Arc<Pipeline>,
322:     mut input: S,
323:     mut output: Sender<EnrichedEvent>,
324: ) -> Result<(), PipelineError>
325: where
326:     S: Stream<Item = SocialEvent> + Unpin + Send + 'static,
327: {
328:     info!("starting pipeline loop");
329: 
330:     let mut in_flight: FuturesUnordered<
331:         Pin<Box<dyn Future<Output = (Result<EnrichedEvent, PipelineError>, SystemTime)> + Send>>,
332:     > = FuturesUnordered::new();
333: 
334:     loop {
335:         select! {
336:             maybe_event = input.next(), if in_flight.len() < MAX_CONCURRENT_EVENTS => {
337:                 match maybe_event {
338:                     Some(event) => {
339:                         let span = tracing::info_span!("process_event", event_id=%event.event_id);
340:                         let fut = {
341:                             let p = pipeline.clone();
342:                             async move {
343:                                 let started = SystemTime::now();
344:                                 let res = p.process_event(event).await;
345:                                 (res, started)
346:                             }
347:                         };
348:                         in_flight.push(Box::pin(fut).instrument(span));
349:                     }
350:                     None => {
351:                         debug!("input stream exhausted");
352:                         break;
353:                     }
354:                 }
355:             }
356: 
357:             Some((res, started)) = in_flight.next() => {
358:                 match res {
359:                     Ok(enriched) => {
360:                         let latency = SystemTime::now().duration_since(started).unwrap_or_default();
361:                         histogram!("pipeline.event.latency_ms", latency.as_millis() as f64);
362:                         if let Err(err) = output.send(enriched).await {
363:                             error!(error=%err, "failed to forward enriched event");
364:                             return Err(PipelineError::ChannelClosed);
365:                         }
366:                     }
367:                     Err(err) => {
368:                         warn!(%err, "discarding event due to error");
369:                         counter!("pipeline.event.discarded", 1, "reason" => format!("{err:?}"));
370:                     }
371:                 }
372:             }
373: 
374:             else => {
375:                 // All events processed and no new events incoming.
376:                 break;
377:             }
378:         }
379:     }
380: 
381:     Ok(())
382: }
